  // Email validation but no uniqueness check
  emails.forEach((emailObj, index) => {
    if (emailObj.email) {
      const emailValidation = validateEmail(emailObj.email);
      if (!emailValidation.isValid) {
        newErrors[`email_${index}`] = emailValidation.error;
      }
    }
  });
}

